export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function getScrollTop(element) {
    return element ? element.scrollTop : 0;
}

@page "/chat"
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name-row">
                            <span class="channel-name"># @channel.Name</span>
                            @if (channel.UnreadCount > 0)
                            {
                                <span class="unread-badge">@channel.UnreadCount</span>
                            }
                        </div>
                        <span class="channel-desc">@Truncate(channel.Description, 50)</span>
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="message-area @(_threadOpen ? "thread-open" : "")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <span class="header-desc">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="HandleScrollAsync">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-bubble" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-top">
                                <span class="msg-author">@msg.Author</span>
                                <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="msg-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => AddReactionAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @if (_threadSummaries.TryGetValue(msg.Id, out var summary))
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies") &middot;
                                    Last reply @FormatRelativeTime(summary.LastReplyAt)
                                </button>
                            }

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" @onclick="() => OpenThreadAsync(msg)"
                                            title="Reply in thread">💬 Reply</button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" @onclick="() => ToggleEmojiPicker(msg.Id)"
                                                title="Add reaction">😀 React</button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newMessageText" @bind:event="oninput"
                          @onkeydown="HandleMessageKeyDownAsync"
                          placeholder="Type a message…" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="msg-author">@_threadRootMessage.Author</span>
                <span class="msg-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <div class="msg-content">@_threadRootMessage.Content</div>
            </div>

            <div class="thread-messages">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="message-bubble thread-reply">
                            <div class="message-top">
                                <span class="msg-author">@reply.Author</span>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => AddReactionAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_threadReplyText" @bind:event="oninput"
                          @onkeydown="HandleThreadKeyDownAsync"
                          placeholder="Reply in thread…" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private Channel? _activeChannel;
    private int? _activeChannelId;

    private List<Message>? _messages;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private bool _loadingMore;
    private bool _allLoaded;

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;

    private string _newMessageText = "";
    private string _threadReplyText = "";
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    private ElementReference _messageListRef;
    private IJSObjectReference? _jsModule;

    private readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-ffd1c9a9b99c4fbbadd7a8ea2eb0bae5/Components/Pages/Chat.razor.js");
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id)
            return;

        _activeChannel = channel;
        _activeChannelId = channel.Id;
        _messages = null;
        _allLoaded = false;
        _threadSummaries.Clear();
        _emojiPickerMessageId = null;

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        _channels = await ChatService.GetChannelsAsync();

        await ScrollToBottomAsync();
    }

    private async Task HandleScrollAsync()
    {
        if (_loadingMore || _allLoaded || _messages is null || _activeChannelId is null)
            return;

        if (_jsModule is null)
            return;

        var scrollTop = await _jsModule.InvokeAsync<double>("getScrollTop", _messageListRef);
        if (scrollTop > 50)
            return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        if (older.Count == 0)
        {
            _allLoaded = true;
        }
        else
        {
            _messages.InsertRange(0, older);
            BuildThreadSummaries();
        }

        _loadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null || _messages is null)
            return;

        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages.Add(msg);
        _newMessageText = "";

        await ScrollToBottomAsync();
    }

    private async Task HandleMessageKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadReplyText = "";
        _emojiPickerMessageId = null;

        var allThreadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadReplies = allThreadMessages.Where(m => m.Id != rootMessage.Id).ToList();

        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplies?.Add(reply);
        _threadReplyText = "";

        // Update thread summary in main view
        if (_threadReplies is not null)
        {
            _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
                _threadRootMessage.Id,
                _threadReplies.Count,
                reply.SentAt);
        }
    }

    private async Task HandleThreadKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh messages to reflect the new reaction
        if (_activeChannelId is not null && _messages is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messages.Count);
            _messages = refreshed;
        }

        // Also refresh thread if open
        if (_threadOpen && _threadRootMessage is not null)
        {
            var allThreadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
            _threadRootMessage = allThreadMessages.FirstOrDefault(m => m.Id == _threadRootMessage.Id) ?? _threadRootMessage;
            _threadReplies = allThreadMessages.Where(m => m.Id != _threadRootMessage.Id).ToList();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private void BuildThreadSummaries()
    {
        if (_messages is null) return;

        _threadSummaries.Clear();
        var replyGroups = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replyGroups)
        {
            var replies = group.ToList();
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                replies.Count,
                replies.Max(r => r.SentAt));
        }
    }

    private async Task ScrollToBottomAsync()
    {
        await Task.Yield();
        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef);
            }
            catch (JSException) { }
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength), "…");

    async ValueTask IAsyncDisposable.DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try { await _jsModule.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }
    }
}

